#!/usr/bin/env node

const fs = require('node:fs');
const path = require('node:path');

const variants = ['Line', 'Fill', 'Duotone', 'Colour'];
const sizes = ['10px', '16px', '20px', '24px', '32px', '48px'];

function createIconDirectories(baseDir = 'public/assets/icons') {
  const fullPath = path.join(process.cwd(), baseDir);
  
  console.log('🎨 Creating icon directory structure...\n');
  
  variants.forEach(variant => {
    sizes.forEach(size => {
      const dir = path.join(fullPath, variant, size);
      
      if (fs.existsSync(dir)) {
        console.log(`⏭️  Already exists: ${variant}/${size}`);
      } else {
        fs.mkdirSync(dir, { recursive: true });
        console.log(`✅ Created: ${variant}/${size}`);
      }
    });
  });
  
  console.log('\n✨ Icon directory structure created successfully!');
  console.log(`📁 Location: ${fullPath}\n`);
  console.log('Next steps:');
  console.log('1. Add your SVG icons to the appropriate folders');
  console.log('2. Use naming convention:');
  console.log('   - For 10px & 16px: icon-name.svg');
  console.log('   - For 20px, 24px, 32px, 48px: icon-name--{size}.svg\n');
}

// Check if custom path is provided
const customPath = process.argv[2];
createIconDirectories(customPath);
